={{
(() => {
  // 1. Safe data fetch (Prevents "undefined" error)
  const nodeName = "Email Trigger (IMAP)";
  const raw = $(nodeName).item.json.textHtml || "";
  if (!raw) return "No content found";

  let clean = raw;

  // 2. Fix Mojibake using Unicode Escapes (The "Magic" Fix)
  // \u00e2\u0080\u0099 = â€™ (Apostrophe)
  // \u00c2\u00a0 = Â (Non-breaking space)
  // \u00e2\u0080\u0093 = â€“ (En Dash)
  clean = clean
    .replace(/\u00e2\u0080\u0099/g, "'")
    .replace(/\u00e2\u0080\u0098/g, "'")
    .replace(/\u00c2\u00a0/g, " ")
    .replace(/\u00c2/g, "")
    .replace(/\u00e2\u0080\u0093/g, "-")
    .replace(/\u00e2\u0080\u00a6/g, "...");

  // 3. Handle HTML structure before stripping tags
  clean = clean
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<\/p>/gi, '\n\n')
    .replace(/<\/div>/gi, '\n');

  // 4. Strip HTML tags
  clean = clean.replace(/<[^>]+>/g, '');

  // 5. Fix common HTML entities
  const entities = {
    '&amp;': '&',
    '&lt;': '<',
    '&gt;': '>',
    '&quot;': '"',
    '&#39;': "'",
    '&nbsp;': ' '
  };

  clean = clean.replace(/&amp;|&lt;|&gt;|&quot;|&#39;|&nbsp;/g, (m) => entities[m]);

  // 6. Clean up whitespace
  return clean
    .replace(/[^\S\r\n]+/g, ' ') // Collapse multiple spaces (but keep newlines)
    .replace(/\n\s*\n\s*\n/g, '\n\n') // Collapse excessive newlines
    .trim();
})()
}}
